const html = $input.first().json.data;

const extract = (pattern) => {
  const results = [];
  const re = new RegExp(pattern, 'g');
  let m;
  while ((m = re.exec(html)) !== null) results.push(m[1].trim());
  return results;
};

const suppliers = extract('class="productSupplier">([^<]+)<');
const dates     = extract('class="headline sub-bold">([^<]+)<');
const dishes    = extract('class="dishInfo">([^<]+)<');
const prices    = extract('class="productPrice">([^<]+)<');

const today = new Date();
const dayNames = ['Sonntag','Montag','Dienstag','Mittwoch','Donnerstag','Freitag','Samstag'];
const todayStr = today.toLocaleDateString('de-DE', {day:'2-digit', month:'2-digit', year:'numeric'});
const todayFull = `${dayNames[today.getDay()]}, ${todayStr}`;

const items = dates.map((d, i) => ({
  supplier: suppliers[i] || '',
  date: d,
  dish: (dishes[i] || '').replace(/\s+/g, ' '),
  price: prices[i] || ''
}));

const wochengericht = items.find(i => i.supplier.includes('Wochengericht'));
const tagesgericht  = items.find(i => i.date === todayFull);

let message = `🍽️ Globus Mittagstisch Braunschweig\n`;
message += `📅 ${todayFull}\n`;
message += `──────────────────\n\n`;

if (wochengericht) {
  message += `🥘 Wochengericht\n${wochengericht.dish}\n💰 ${wochengericht.price}\n\n`;
}

if (tagesgericht) {
  message += `🍳 Tagesgericht\n${tagesgericht.dish}\n💰 ${tagesgericht.price}\n`;
} else {
  message += `ℹ️ Kein Tagesgericht für heute.\nhttps://www.globus.de/braunschweig/unser-restaurant.php`;
}

return [{ json: { message } }];

